   export const isArmstrongNumber = (n) => {
     const digits = String(n).split('');
     const power = digits.length;
     const sum = digits.reduce((acc, d) => acc + BigInt(d) ** BigInt(power), 0n);
     return sum === BigInt(n);
   };
